def _to_snake_case(flag_name):
    """Convert a camelCase or PascalCase flag name to snake_case."""
    normalized = []
    for char in flag_name:
        if char.isupper():
            normalized.append("_")
            normalized.append(char.lower())
        else:
            normalized.append(char)
    return "".join(normalized).lstrip("_")


def is_enabled(flag_name):
    """Check if a feature flag is enabled.

    Args:
        flag_name: the flag key to look up (may be camelCase or snake_case)

    Returns:
        True if the flag is enabled, False otherwise.
    """
    normalized_flag_name = _to_snake_case(flag_name)
    return FLAGS.get(normalized_flag_name, False)


